using System.Text.Json; using Exam.Core; namespace Exam.Data; public sealed class MaterialRepository{readonly string path; public MaterialRepository(string? b=null){path=Path.Combine(b??AppContext.BaseDirectory,"resources","seed-materials.json");} public List<Material> Load()=>File.Exists(path)?JsonSerializer.Deserialize<List<Material>>(File.ReadAllText(path))??new():new(); public void Save(IEnumerable<Material> x){Directory.CreateDirectory(Path.GetDirectoryName(path)!);File.WriteAllText(path,JsonSerializer.Serialize(x,new JsonSerializerOptions{WriteIndented=true}));} public bool CanDelete(Material x)=>!x.HasProductMaterial;}
